const amqp = require('amqplib');

// RabbitMQ connection settings
const rabbitUrl = 'amqp://localhost';
const queueName = 'payment_events';

async function main() {
  try {
    // Establish a connection to the RabbitMQ server
    const connection = await amqp.connect(rabbitUrl);
    
    // Create a channel for publishing messages
    const channel = await connection.createChannel();
    
    // Declare the payment events queue if it doesn't exist
    await channel.assertQueue(queueName, { durable: true });
    
    console.log(`Waiting for messages in ${queueName}...`);
    
    // Consume messages from the queue
    channel.consume(queueName, (msg) => {
      if (msg !== null) {
        const paymentEvent = JSON.parse(msg.content.toString());
        
        // Execute payment logic directly based on message content
        executePayment(paymentEvent);
        
        // Acknowledge the message to indicate it's been processed
        channel.ack(msg);
      }
    });
  } catch (err) {
    console.error('Error:', err);
  }
}

// Payment processing function
async function executePayment(paymentEvent) {
  try {
    const paymentAmount = parseFloat(paymentEvent.amount);
    const paymentMethod = paymentEvent.method;
    
    // Simulate a payment processing operation
    await new Promise((resolve, reject) => {
      setTimeout(() => {
        if (paymentMethod === 'credit_card') {
          console.log(`Payment processed successfully for ${paymentAmount} using credit card.`);
          resolve();
        } else {
          console.error(`Error processing payment: Unsupported payment method.`);
          reject(new Error('Unsupported payment method'));
        }
      }, 1000);
    });
    
    // Update the database with the payment status
    await updateDatabase(paymentEvent.id, 'paid');
  } catch (err) {
    console.error('Error executing payment:', err);
  }
}

// Simulate a database operation to update the payment status
async function updateDatabase(paymentId, status) {
  try {
    // Replace this with your actual database connection and query logic
    const db = require('./db'); // Assuming you have a separate db module
    
    await db.query(`UPDATE payments SET status = $1 WHERE id = $2`, [status, paymentId]);
    
    console.log(`Payment status updated successfully for ${paymentId}.`);
  } catch (err) {
    console.error('Error updating database:', err);
  }
}

